def stage_names() -> tuple[str, ...]:
    return tuple(stage["stage"] for stage in RUNTIME_SCRIPT_TRACE_MAP)

def get_stage(stage_name: str) -> dict[str, Any]:
    wanted = stage_name.strip().upper()
    for stage in RUNTIME_SCRIPT_TRACE_MAP:
        if stage["stage"] == wanted:
            return dict(stage)
    raise KeyError(stage_name)

def validate_stage_order(observed_stage_order: Iterable[str]) -> bool:
    return tuple(observed_stage_order) == CANONICAL_RUNTIME_STAGE_ORDER

def validate_exact_script_bindings() -> bool:
    if stage_names() != CANONICAL_RUNTIME_STAGE_ORDER:
        return False
    required = {
        "stage","executing_script","executing_language","python_script","repo_modules",
        "launch_location","working_directory_before","working_directory_after","commands",
        "purpose","writes_repo","writes_remote","raw_artifacts","repo_evidence",
        "next_stage","forbidden","grants_authority","closes_wound","repairs_code"
    }
    for stage in RUNTIME_SCRIPT_TRACE_MAP:
        if not required.issubset(stage):
            return False
        if not stage["stage"] or not stage["executing_script"] or not stage["purpose"]:
            return False
        if "python_script" not in stage or "repo_modules" not in stage:
            return False
        if not (stage["launch_location"] or stage["working_directory_before"] or stage["working_directory_after"]):
            return False
        if stage.get("grants_authority") is not False or stage.get("closes_wound") is not False:
            return False
        if stage.get("repairs_code") is not False or stage.get("claims_current_operation_ci_green") is not False:
            return False
    return True

